SELECT COUNT(*) AS total_predictions
FROM risk_predictions
WHERE iso = '1' AND year = 2015;

SELECT country_name
FROM countries
WHERE iso = '1';

SELECT COUNT(*) 
FROM risk_predictions 
WHERE team_id = '0' AND year = 2023;

SELECT AVG(confidence_level) AS average_confidence
FROM risk_predictions
WHERE team_id = '0' AND year = 2015;

SELECT AVG(confidence_level) AS average_confidence_level_2023
FROM risk_predictions
WHERE team_id = 'LUIGI' AND year = 2023;

SELECT expert_name 
FROM experts 
WHERE expert_id = '0';

SELECT prediction
FROM risk_predictions
WHERE iso = 'GB' AND year = 2023;

SELECT iso, year
FROM risk_predictions
WHERE confidence_level > 0.7;

SELECT iso, prediction
FROM risk_predictions
WHERE iso = '1' AND year = 1;

SELECT iso, year, prediction, confidence_level
FROM risk_predictions
ORDER BY confidence_level DESC;

SELECT iso, year, prediction, team_id, MAX(confidence_level) AS max_confidence
FROM risk_predictions
GROUP BY iso, year, prediction, team_id;

SELECT AVG(country_avg) AS overall_average_prediction
FROM (
    SELECT AVG(prediction) AS country_avg
    FROM risk_predictions
    GROUP BY iso
) AS country_averages;
